#include<bits/stdc++.h>
using namespace std;
long long dp[205],n,m,a[25],b[25];
long long fun(int x,int y)
{
    long long ans=1;
    for(int i=1;i<=y;i++)
    {
        ans*=x;
    }
    return ans;
}
int main()
{
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>a[i]>>b[i];
	}
    memset(dp,0x3f,sizeof(dp));
    dp[0]=0;
	for(int i=1;i<=m;i++)
	{
		for(int j=n;j>=1;j--)
        {
            for(int k=0;k<=j;k++)
            {
                int t=j-k;
                dp[j]=min(dp[j],dp[k]+a[i]*fun(t,b[i]));
            }
        }
	}
    cout<<dp[n];
	return 0;
}
